import { BedrockAgentRuntimeClient, InvokeAgentCommand } from '@aws-sdk/client-bedrock-agent-runtime';
import PII_REGEX from 'pii-regex';

const client = new BedrockAgentRuntimeClient({ region: 'us-east-1' });

async function invokeAgentWithPIICheck(agentId: string, sessionId: string, input: string) {
  const command = new InvokeAgentCommand({
    agentId,
    agentAliasId: 'TSTALIASID',
    sessionId,
    inputText: input
  });

  const response = await client.send(command);

  if (response.completion) {
    const chunks = [];
    for await (const chunk of response.completion) {
      const text = new TextDecoder().decode(chunk.chunk?.bytes);
      chunks.push(text);

      if (PII_REGEX().test(text)) {
        console.error('🚨 PII detected in streaming response:', text);
        throw new Error('PII Detection Failed');
      }
    }
    console.log('Full response:', chunks.join(''));
  }
}

