import json
import re

def lambda_handler(event, context):
    # Database query result
    raw_data = {
        'customer': 'John Doe',
        'ssn': '123-45-6789',
        'phone': '555-123-4567'
    }

    # Redact PII
    safe_data = {
        'customer': raw_data['customer'],
        'ssn': '[REDACTED]',
        'phone': '[REDACTED]',
        'summary': 'Customer account active'
    }

    return {
        'statusCode': 200,
        'body': json.dumps(safe_data),
        'sessionAttributes': {
            'pii_processed': True
        }
    }

import { redactedPII } from 'pii-redact';

function createPIIMiddleware() {
  return async (req: any, res: any, next: any) => {
    const originalJson = res.json;

    res.json = function (data: any) {
      if (typeof data === 'string') {
        data = redactedPII(data, {
          patterns: ['SSN', 'CREDIT_CARD', 'PHONE'],
          replacement: '[REDACTED]'
        });
      }
      return originalJson.call(this, data);
    };

    next();
  };
}

const piiMiddleware = createPIIMiddleware();

